  1	import * as React from 'react';
  2	import { IamUserDetails } from '@odf/core/types';
  3	import PageHeading from '@odf/shared/heading/page-heading';
  4	import { useRefresh } from '@odf/shared/hooks';
  5	import { BlueSyncIcon } from '@odf/shared/status';
  6	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  7	import Tabs, { TabPage } from '@odf/shared/utils/Tabs';
  8	import { useModal } from '@openshift-console/dynamic-plugin-sdk';
  9	import { LaunchModal } from '@openshift-console/dynamic-plugin-sdk/lib/app/modal-support/ModalProvider';
 10	import { useParams } from 'react-router-dom-v5-compat';
 11	import { Button, ButtonVariant } from '@patternfly/react-core';
 12	import { ActionsColumn } from '@patternfly/react-table';
 13	import { DeleteIamUserModal } from '../../../modals/s3-iam/DeleteIamUserModal';
 14	import { CustomActionsToggle } from '../../s3-browser/objects-list';
 15	import { AccessKeysDetails } from '../access-keys-details/AccessKeysDetails';
 16	import { IamContext, IamProvider } from '../iam-context';
 17	import { TagsDetails } from '../tags-details/TagsDetails';
 18	
 19	const UserOverview: React.FC<{}> = () => {
 20	  const { t } = useCustomTranslation();
 21	  const [fresh, triggerRefresh] = useRefresh();
 22	  const { userName } = useParams();
 23	  const launcher = useModal();
 24	
 25	  const navPages: TabPage[] = React.useMemo(
 26	    () => [
 27	      {
 28	        href: 'details',
 29	        name: t('Details'),
 30	        component: TagsDetails,
 31	      },
 32	      {
 33	        href: 'access-keys',
 34	        name: t('Access Keys'),
 35	        component: AccessKeysDetails,
 36	      },
 37	    ],
 38	    [t]
 39	  );
 40	
 41	  const breadcrumbs = React.useMemo(
 42	    () => [
 43	      {
 44	        name: t('Object Storage'),
 45	        path: '/odf/object-storage',
 46	      },
 47	      {
 48	        name: t('IAM'),
 49	        path: '/odf/object-storage/iam',
 50	      },
 51	      {
 52	        name: t('User'),
 53	        path: '',
 54	      },
 55	    ],
 56	    [t]
 57	  );
 58	
 59	  return (
 60	    <IamProvider>
 61	      <UserOverviewContent
 62	        breadcrumbs={breadcrumbs}
 63	        fresh={fresh}
 64	        triggerRefresh={triggerRefresh}
 65	        navPages={navPages}
 66	        userName={userName}
 67	        launcher={launcher}
 68	      />
 69	    </IamProvider>
 70	  );
 71	};
 72	
 73	type UserOverviewContentProps = {
 74	  breadcrumbs: { name: string; path: string }[];
 75	  fresh: boolean;
 76	  triggerRefresh: () => void;
 77	  navPages: TabPage[];
 78	  userName: string;
 79	  launcher: LaunchModal;
 80	};
 81	
 82	const UserOverviewContent: React.FC<UserOverviewContentProps> = ({
 83	  breadcrumbs,
 84	  fresh,
 85	  triggerRefresh,
 86	  navPages,
 87	  userName,
 88	  launcher,
 89	}) => {
 90	  const { t } = useCustomTranslation();
 91	  const { iamClient } = React.useContext(IamContext);
 92	
 93	  const handleDeleteUser = React.useCallback(
 94	    () =>
 95	      launcher(DeleteIamUserModal, {
 96	        isOpen: true,
 97	        extraProps: {
 98	          userName,
 99	          iamClient,
100	          refreshTokens: triggerRefresh,
101	        },
102	      }),
103	    [launcher, userName, iamClient, triggerRefresh]
104	  );
105	  const getUsersActionsItems = React.useMemo(
106	    () => [
107	      {
108	        title: t('Delete user'),
109	        onClick: handleDeleteUser,
110	      },
111	    ],
112	    [t, handleDeleteUser]
113	  );
114	
115	  const renderActions = React.useMemo(
116	    () => (
117	      <>
118	        <Button
119	          className="pf-v6-u-mr-md pf-v6-u-mb-xs"
120	          variant={ButtonVariant.link}
121	          icon={<BlueSyncIcon />}
122	          onClick={triggerRefresh}
123	          isDisabled={!fresh}
124	          isInline
125	        >
126	          {t('Refresh')}
127	        </Button>
128	
129	        <ActionsColumn
130	          items={getUsersActionsItems}
131	          actionsToggle={CustomActionsToggle}
132	        />
133	      </>
134	    ),
135	    [t, fresh, triggerRefresh, getUsersActionsItems]
136	  );
137	
138	  const customData: IamUserDetails = React.useMemo(
139	    () => ({
140	      fresh,
141	      triggerRefresh,
142	      userName,
143	      iamClient,
144	    }),
145	    [fresh, triggerRefresh, userName, iamClient]
146	  );
147	
148	  return (
149	    <>
150	      <PageHeading
151	        breadcrumbs={breadcrumbs}
152	        title={userName}
153	        actions={() => renderActions}
154	        className="pf-v6-u-mt-md"
155	      />
156	      <Tabs id="iam-overview" tabs={navPages} customData={customData} />
157	    </>
158	  );
159	};
160	
161	export default UserOverview;

